8	import Foundation
9	import Combine
10	import FactoryKit
11	
12	@Observable
13	final class DeviceListViewModel {
14	    
15	    enum ViewType {
16	        case `default`
17	        case noDevices
18	        case bluetoothDisabled
19	        case bluetoothNotAuthorized
20	    }
21	    
22	    @ObservationIgnored
23	    @Injected(\.deviceFoundManager) private var deviceFoundManager
24	    @ObservationIgnored
25	    @Injected(\.deviceConnectionManager) private var deviceConnectionManager
26	    @ObservationIgnored
27	    @Injected(\.bluetoothManager) private var bluetoothManager
28	    
29	    var isSearching: Bool = false
30	    var devices: [RadiaCode] = []
31	    var viewType: ViewType = .default
32	
33	    @ObservationIgnored
34	    private var cancellable: Set<AnyCancellable> = .init()
35	
36	    func fetch(currentDeviceIdentifier: String?) {
37	        deviceFoundManager.startSearching()
38	        
39	        deviceFoundManager.observeSearchingState
40	            .receive(on: DispatchQueue.main)
41	            .sink { [weak self] in
42	                self?.isSearching = $0
43	            }
44	            .store(in: &cancellable)
45	        
46	        deviceFoundManager.foundDeviceObserver
47	            .filter { $0.device.identifier != currentDeviceIdentifier }
48	            .collect(.byTime(DispatchQueue.main, .seconds(0.5)))
49	            .map { Set<RadiaCode>($0) }
50	            .map { $0.sorted { $0.signal.value > $1.signal.value } }
51	            .receive(on: DispatchQueue.main)
52	            .sink(receiveCompletion: { _ in }, receiveValue: { [weak self] batch in
53	                guard let self else { return }
54	                self.devices.append(contentsOf: batch.filter { !self.devices.contains($0) })
55	            })
56	            .store(in: &cancellable)
57	        
58	        bluetoothManager.bluetoothStatus
59	            .receive(on: DispatchQueue.main)
60	            .sink { [weak self] status in
61	                guard let self else { return }
62	                switch status {
63	                case .notAuthorized:
64	                    viewType = .bluetoothNotAuthorized
65	                case .poweredOn, .unknown:
66	                    viewType = .default
67	                case .poweredOff:
68	                    viewType = .bluetoothDisabled
69	                }
70	            }
71	            .store(in: &cancellable)
72	        
73	        if currentDeviceIdentifier == nil {
74	            startNotFoundCheck()
75	        }
76	    }
77	    
78	    func connect(radiacode: RadiaCode) {
79	        Task {
80	            await deviceConnectionManager.connect(radiacode: radiacode)
81	        }
82	    }
83	        
84	    func startNotFoundCheck() {
85	        viewType = .default
86	        Task {
87	            try? await Task.sleep(seconds: 30)
88	            if self.devices.isEmpty {
89	                await MainActor.run {
90	                    viewType = .noDevices
91	                }
92	            }
93	        }
94	    }
95	        
96	    deinit {
97	        deviceFoundManager.stopSearching()
98	    }
99	}
